document.addEventListener('click',async e=>{const a=e.target.closest('[data-load-comments]');if(a){const id=a.dataset.loadComments;const box=document.querySelector('[data-comments-for="'+id+'"]');if(box&&!box.dataset.loaded){box.textContent='Loading comments...';const r=await fetch('/api/comments?contentId='+encodeURIComponent(id)).catch(()=>null);box.textContent=r?'Comments loaded.':'Comments unavailable.';box.dataset.loaded='1';}}});